+            onClick={onClose}
+            className="px-4 py-2 rounded-lg bg-muted hover:bg-muted/80 text-sm font-medium text-foreground transition-colors"
+          >
+            Done
+          </button>
+        </div>
+      </div>
+    </>,
+    document.body
+  );
+}

